import{c as t,Q as o,j as d,m as a}from"./chunks/framework.CTNaDwNv.js";const p=JSON.parse('{"title":"Security model","description":"","frontmatter":{},"headers":[],"relativePath":"reference/security.md","filePath":"reference/security.md","lastUpdated":1779853631000}'),r={name:"reference/security.md"};function n(c,e,s,l,i,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="security-model" tabindex="-1">Security model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security model&quot;">​</a></h1><p><code>agent_api</code> runs in your live FiveM server&#39;s process and can move money in ESX, kick players, run SQL, and rewrite resources. Every part of the design assumes the token might leak; layered defences keep one mistake from being catastrophic.</p><h2 id="defence-layers" tabindex="-1">Defence layers <a class="header-anchor" href="#defence-layers" aria-label="Permalink to &quot;Defence layers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Enforced by</th><th>What it stops</th></tr></thead><tbody><tr><td>1 — Token</td><td><code>x-agent-token</code> header check on every request except <code>GET /health</code></td><td>Random scanners on <code>:30120</code></td></tr><tr><td>2 — Body limit</td><td>5 MB cap, returns <code>BODY_TOO_LARGE</code></td><td>Denial via oversized POST</td></tr><tr><td>3 — Rate limit</td><td>Token bucket, 120 req/min default per token hash, returns <code>RATE_LIMITED</code></td><td>Runaway agent loops</td></tr><tr><td>4 — JSON parse</td><td>Throws <code>INVALID_INPUT</code> on malformed JSON</td><td>Garbage payloads</td></tr><tr><td>5 — zod schema</td><td>Per-tool <code>.strict()</code> schema</td><td>Unknown fields, wrong types</td></tr><tr><td>6 — Readonly mode</td><td><code>agent_api_readonly=true</code> blocks every mutating tool</td><td>Production lock-down</td></tr><tr><td>7 — Path sandbox</td><td><code>sandbox.ts</code> + per-tool checks</td><td><code>..</code>, absolute paths, <code>txData/.env/database/cache</code> segments, writes outside configured roots</td></tr><tr><td>8 — Extension allowlist</td><td><code>WRITE_EXTENSIONS</code> set</td><td>Writing <code>.exe</code>, <code>.sh</code>, binary blobs</td></tr><tr><td>9 — Verb allowlist</td><td><code>parseAllowedCommand</code> for <code>run_command</code></td><td>Banned console verbs (<code>quit</code>, <code>exec</code>, <code>add_ace</code>, <code>rcon_password</code>, …)</td></tr><tr><td>10 — ACE</td><td>FiveM&#39;s own ACL on <code>command.*</code></td><td>Agent calling lifecycle verbs without server permission</td></tr><tr><td>11 — Per-resource lock</td><td><code>withLock(name, fn)</code></td><td>Two mutators racing on the same resource</td></tr><tr><td>12 — Self-target guard</td><td><code>runLifecycle</code> refuses if resource = <code>agent_api</code></td><td>A known FiveM Mono SIGSEGV</td></tr><tr><td>13 — Subject opt-in</td><td><code>/agent_test_optin</code> chat command + TTL session</td><td>Acting on non-consenting players</td></tr><tr><td>14 — Native blocklists</td><td>Per-tool blocklists + a built-in danger list</td><td><code>DropPlayer</code>, <code>ExecuteCommand</code>, <code>StopResource</code> via reflective natives</td></tr><tr><td>15 — Plugin gates</td><td>Per-plugin convars (e.g. <code>agent_api_plugin_oxmysql_readonly</code>)</td><td>Open SQL access by default</td></tr><tr><td>16 — Audit log</td><td>Append-only <code>dist/audit.log</code> JSONL</td><td>Forensics after the fact</td></tr></tbody></table><h2 id="token-handling" tabindex="-1">Token handling <a class="header-anchor" href="#token-handling" aria-label="Permalink to &quot;Token handling&quot;">​</a></h2><ul><li><strong>Storage.</strong> <code>dist/.agent_token</code>, mode <code>0600</code> on POSIX. Gitignored.</li><li><strong>In transit.</strong> <code>x-agent-token</code> header. We do not log the full token anywhere — the audit log records <code>sha256(token).slice(0, 12)</code> only.</li><li><strong>Rotation.</strong> <code>rm dist/.agent_token &amp;&amp; restart agent_api</code>. The console prints a new MCP config block with the new token.</li></ul><h2 id="network-exposure" tabindex="-1">Network exposure <a class="header-anchor" href="#network-exposure" aria-label="Permalink to &quot;Network exposure&quot;">​</a></h2><ul><li>Default bind: <code>127.0.0.1</code>. The FiveM HTTP handler does not expose <code>agent_api/*</code> paths externally unless you&#39;ve opened <code>30120</code> to the internet (don&#39;t).</li><li>For remote dev, SSH-tunnel <code>30120</code> to your dev machine.</li></ul><h2 id="reflective-dispatch-—-what-makes-it-safe" tabindex="-1">Reflective dispatch — what makes it safe <a class="header-anchor" href="#reflective-dispatch-—-what-makes-it-safe" aria-label="Permalink to &quot;Reflective dispatch — what makes it safe&quot;">​</a></h2><p>Reflective tools (<code>server_call_native</code>, <code>client_call_native</code>, <code>esx_call_player</code>, <code>oxlib_call</code>) can in principle call anything. They survive review because of three layered checks:</p><ol><li><strong>Built-in danger blocklist</strong> (server only) — <code>DropPlayer</code>, <code>ExecuteCommand</code>, etc. always refused regardless of <code>readonly</code>.</li><li><strong>Convar blocklist</strong> — operator-controlled, applies to every reflective call.</li><li><strong>Readonly verb heuristic</strong> — when <code>readonly=true</code>, only method names starting with <code>Get/Has/Is/Does/Can/Will/Network</code> pass. Anything else (<code>Set</code>, <code>Add</code>, <code>Delete</code>, <code>Drop</code>, <code>Spawn</code>, …) refused.</li></ol><p>These layers compose. Even with <code>readonly=false</code> (the dev default), <code>DropPlayer</code> is still blocked.</p><h2 id="what-s-intentionally-not-defended" tabindex="-1">What&#39;s intentionally NOT defended <a class="header-anchor" href="#what-s-intentionally-not-defended" aria-label="Permalink to &quot;What&#39;s intentionally NOT defended&quot;">​</a></h2><ul><li><strong>A compromised host machine.</strong> If an attacker can read <code>dist/.agent_token</code>, they can act as the agent.</li><li><strong>A malicious server operator.</strong> The operator controls every convar. If they turn off rate limit, sandbox, and blocklist, then hand the token to a third party, that&#39;s on them.</li><li><strong>A malicious agent.</strong> A misbehaving LLM agent can still spam allowed calls. We have rate limit + audit log, not behavioural detection.</li></ul><h2 id="responsible-disclosure" tabindex="-1">Responsible disclosure <a class="header-anchor" href="#responsible-disclosure" aria-label="Permalink to &quot;Responsible disclosure&quot;">​</a></h2><p>Sandbox bypasses, gate-circumvention paths, or anything that lets a caller escape the readonly/blocklist surfaces should be reported privately to <strong><a href="mailto:fx.frame009@gmail.com" target="_blank" rel="noreferrer">fx.frame009@gmail.com</a></strong> before any public issue. See <a href="https://github.com/mysbryce/5m-mcp/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a>.</p>',16)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
